import axios from 'axios';

async function testGradio() {
    const tinyImage = "data:image/jpeg;base64,";
    
    try {
        console.log("Testing HuggingFace Gradio API...");
        const res = await axios.post("https://akhaliq-real-esrgan.hf.space/run/predict", {
            data: [tinyImage, "version 1.4", 2]
        }, { timeout: 30000 });
        
        console.log("Status:", res.status);
        console.log("Data:", JSON.stringify(res.data).slice(0, 200));
    } catch (e) {
        console.log("Failed:", e.response?.data || e.message);
    }
}

testGradio();
